+  return (
+    <Command>
+      <CommandList className="max-h-fit">
+        <CommandGroup>
+          <div>
+            <Calendar
+              defaultMonth={date?.from}
+              initialFocus
+              mode="range"
+              numberOfMonths={1}
+              onSelect={changeDateRange}
